sys_ui_action.script:
function onClickSetPending() {
    // Per AAP Section 0.5.5 (In Progress -> Pending):
    //   "None; sets pending_reason (Awaiting Info / Awaiting Third Party / Other)"
    //
    // This is the CLIENT-side entry point invoked via the <onclick> field
    // when the user clicks the "Set Pending" form button. It runs in the
    // browser (window is defined, g_form is available) and is responsible
    // for:
    //   1) Defense-in-depth re-check that status is still 'In Progress'
    //      (the visibility <condition> already gated the button at form
    //      render time, but the user could have edited a hidden form
    //      field via DevTools or a separate browser tab could have
    //      transitioned the case in the meantime).
    //   2) Prompting the user for the pending_reason value.
    //   3) Validating the input against the three allowed Choice labels.
    //   4) Stamping the chosen reason onto the form so the server can
    //      read it as current.pending_reason.
    //   5) Submitting the form via gsftSubmit to invoke the server-side
    //      branch of this UI Action.
    //
    // Returning false from this function aborts the form submit. We
    // ALWAYS return false at the end of the success path because
    // gsftSubmit performs the submission asynchronously - allowing the
    // default form submit to also fire would cause a duplicate submit.
    if (g_form.getValue('status') != 'In Progress') {
        g_form.addErrorMessage('Only In Progress cases can be moved to Pending.');
        return false;
    }

    // Prompt the user for the pending_reason. The choices match
    // ../choices/sys_choice_case_pending_reason.xml byte-for-byte:
    //   'Awaiting Info'
    //   'Awaiting Third Party'
    //   'Other'
    // The default value 'Awaiting Info' is the most common reason in
    // the POC seed data and is offered as a sensible starting point.
    var reason = prompt('Enter pending reason (Awaiting Info, Awaiting Third Party, Other):', 'Awaiting Info');
    if (reason === null) {
        // User clicked Cancel on the prompt dialog. Abort the action
        // gracefully without changing the case state or surfacing any
        // error message. This is the standard ServiceNow client-action
        // cancel pattern - returning false suppresses the form submit.
        return false;
    }

    // Trim whitespace defensively. The prompt may return values with
    // accidental leading/trailing whitespace from copy-paste or
    // browser auto-fill. The empty-string fallback handles the case
    // where the user clears the prompt input and clicks OK.
    reason = reason ? reason.trim() : '';

    // Validate against the three allowed Choice labels. The labels are
    // hard-coded here rather than fetched dynamically because:
    //   1) The labels are stable per AAP Section 0.5.7 verbatim and
    //      change only via an AAP amendment.
    //   2) Fetching dynamically would require a server round-trip,
    //      which is unnecessary for a POC and would slow the prompt UX.
    //   3) The server-side defense-in-depth check below also validates
    //      against the same array, so a mismatch is caught even if
    //      the client-side array is somehow out of sync.
    var allowed = ['Awaiting Info', 'Awaiting Third Party', 'Other'];
    if (allowed.indexOf(reason) < 0) {
        g_form.addErrorMessage('Pending reason must be one of: Awaiting Info, Awaiting Third Party, Other.');
        return false;
    }

    // Stash the chosen reason in the form so the server script can read
    // it as current.pending_reason. The g_form.setValue call updates
    // the in-memory form state; the value will be serialized into the
    // form post body when gsftSubmit fires. The pending_reason field
    // is declared in ../dictionary/x_casemgmt_case_pending_reason.xml
    // as a non-mandatory Choice column, so writing to it from here is
    // legal even if the field was previously empty.
    g_form.setValue('pending_reason', reason);

    // Submit the form via the standard ServiceNow UI-Action verb pattern.
    // The verb name is derived from the UI Action's sys_name:
    //   'sysverb_' + sys_name = 'sysverb_x_casemgmt_case_set_pending'
    // The platform recognizes this verb, serializes the form state,
    // posts it to the server, and re-evaluates this <script> body in
    // a server-side sandbox where the `if (typeof window == 'undefined')`
    // guard becomes true and serverSetPending() is invoked.
    gsftSubmit(null, g_form.getFormElement(), 'sysverb_x_casemgmt_case_set_pending');

    // Suppress the default form-submit handler. gsftSubmit already
    // submitted the form; allowing the default to fire would cause a
    // duplicate submit and a confusing user experience.
    return false;
}

// SERVER-SIDE INVOCATION GUARD.
// On the server (sandbox), the `window` global is undefined and
// the `current` GlideRecord is bound by the platform. On the client
// (browser), `window` is defined. This conditional is the canonical
// ServiceNow hybrid UI-Action pattern that delegates server-side
// execution to a named function while the client-side onclick handler
// continues to invoke onClickSetPending() from the browser.
if (typeof window == 'undefined') {
    serverSetPending();
}

function serverSetPending() {
    // SERVER-side entry point invoked when gsftSubmit posts the form
    // back from the client. Runs in the server sandbox (no window, has
    // current GlideRecord, has gs and action). Responsible for:
    //   1) Defense-in-depth role re-check (case_manager OR case_agent).
    //   2) Defense-in-depth status re-check (must be 'In Progress').
    //   3) Defense-in-depth "Assigned only" re-check for case_agents.
    //   4) Defense-in-depth pending_reason re-check (must be one of the
    //      three Choice labels).
    //   5) Status persistence (current.status = 'Pending'; current.update()).
    //   6) Form refresh (action.setRedirectURL(current)).
    //
    // Each of the four guards above maps to a row in the AAP Section
    // 0.5.6 ACL matrix or the AAP Section 0.5.7 data-model contract:
    //   - Guard 1: Role check enforces "Only role X can perform action Y".
    //   - Guard 2: Status check enforces "Only In Progress -> Pending".
    //   - Guard 3: Assigned only check enforces case_agent's assigned-only
    //     write privilege (case_manager bypasses this guard).
    //   - Guard 4: Choice-value check enforces the typed pending_reason
    //     vocabulary.
    //
    // All four guards must pass before current.update() is called.
    // Any guard failure surfaces a blocking gs.addErrorMessage and
    // returns without persisting.

    // Guard 1: Role check. The user must hold case_manager OR case_agent.
    // (case_viewer is excluded by the <roles> field already, but the
    // server-side re-check protects against the rare case where a user
    // gained the role between form load and form submit.)
    if (!gs.getUser().hasRole('x_casemgmt_case_manager') && !gs.getUser().hasRole('x_casemgmt_case_agent')) {
        gs.addErrorMessage('Only case managers and assigned case agents can set a case to Pending.');
        action.setRedirectURL(current);
        return;
    }

    // Guard 2: Status check. The case must currently be In Progress.
    // Re-checking on the server protects against a stale-form attack
    // where the user opens the form when status is In Progress, the
    // case transitions in another tab, then the user submits from the
    // original tab. The check uses string comparison against the
    // verbatim Title Case 'In Progress' label per AAP Section 0.5.7
    // (note the literal SPACE between 'In' and 'Progress').
    if (current.status != 'In Progress') {
        gs.addErrorMessage('Only In Progress cases can be moved to Pending.');
        action.setRedirectURL(current);
        return;
    }

    // Guard 3: Assigned only check for case_agents. case_managers
    // bypass this guard (they can set Pending on any case). For
    // case_agents, the case must be assigned to them directly OR
    // they must be a member of the assigned_group, per AAP Section
    // 0.5.6 verbatim: "Assigned only = cases where assigned_agent =
    // current user OR assigned_group contains current user".
    //
    // The String() coercion via .toString() on assigned_group resolves
    // the GlideElement reference to its sys_id string, which is what
    // gs.getUser().isMemberOf() expects. Without the coercion, the
    // GlideElement-vs-string comparison can behave inconsistently
    // across releases.
    if (gs.getUser().hasRole('x_casemgmt_case_agent') && !gs.getUser().hasRole('x_casemgmt_case_manager')) {
        var groupIdForPending = current.assigned_group ? current.assigned_group.toString() : '';
        var isAssigned = (current.assigned_agent == gs.getUserID()) ||
                         (groupIdForPending && gs.getUser().isMemberOf(groupIdForPending));
        if (!isAssigned) {
            gs.addErrorMessage('Only case managers and assigned case agents can set a case to Pending.');
            action.setRedirectURL(current);
            return;
        }
    }

    // Guard 4: pending_reason value check. The client-side onClickSetPending
    // function should have populated this field with one of the three
    // allowed labels via g_form.setValue('pending_reason', reason).
    // We re-validate on the server because:
    //   - Form data can be tampered with between client and server.
    //   - The UI Action could be invoked via the Table API or scripted
    //     REST in some unusual integration path that bypasses the
    //     client-side prompt.
    //   - Defense-in-depth is the AAP-mandated security posture.
    var reason = current.pending_reason ? current.pending_reason.toString() : '';
    var allowed = ['Awaiting Info', 'Awaiting Third Party', 'Other'];
    if (allowed.indexOf(reason) < 0) {
        gs.addErrorMessage('Pending reason must be one of: Awaiting Info, Awaiting Third Party, Other.');
        action.setRedirectURL(current);
        return;
    }

    // All four guards passed. Perform the In Progress -> Pending
    // transition. The status assignment uses the verbatim Title Case
    // 'Pending' label per AAP Section 0.5.7 and the sibling choice
    // file ../choices/sys_choice_case_status.xml. The current.update()
    // call persists the change and triggers the platform's Business
    // Rule pipeline, including:
    //   - ../business_rules/x_casemgmt_block_terminal_closed.xml
    //     (skipped because previous.status was In Progress, not Closed)
    //   - ../business_rules/x_casemgmt_block_draft_backtransition.xml
    //     (skipped because current.status is Pending, not Draft)
    //   - ../business_rules/x_casemgmt_validate_assigned_agent_membership.xml
    //     (re-validates assigned_agent membership; passes if current
    //      state is consistent)
    //   - ../business_rules/x_casemgmt_clear_pending_reason_on_inprogress.xml
    //     (skipped because previous.status was In Progress and current.status
    //      is Pending, not the reverse Pending -> In Progress transition)
    //   - ../business_rules/x_casemgmt_set_closed_date.xml
    //     (skipped because current.status is Pending, not Closed)
    // The flows ../flows/general_inquiry_state_machine.xml and
    // ../flows/complaint_state_machine.xml also fire on this update,
    // calling the validate_pending_transition subflow which is a no-op
    // for this transition (no required condition; the pending_reason
    // is already set by this UI Action's prior g_form.setValue call).
    current.status = 'Pending';
    current.update();

    // Refresh the form to show the new status. The standard ServiceNow
    // UI-Action pattern is to call action.setRedirectURL(current) which
    // navigates the browser to the same record's form view, picking
    // up the new status and any side-effect field changes.
    action.setRedirectURL(current);
}
